#!/usr/bin/env python
from __future__ import print_function
import os
import sys
import datetime
import subprocess
import shutil

def usage():
    print("Usage: {} <directory> <format>".format(os.path.basename(sys.argv[0])))
    print("Supported formats: tar.gz | tgz | tar.bz2 | tbz2 | zip | 7z")
